extern "C" {
    #[doc = " Create a new mutex.\n\n All newly-created mutexes begin in the _unlocked_ state.\n\n Calls to SDL_LockMutex() will not return while the mutex is locked by\n another thread. See SDL_TryLockMutex() to attempt to lock without blocking.\n\n SDL mutexes are reentrant.\n\n \\returns the initialized and unlocked mutex or NULL on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_DestroyMutex\n \\sa SDL_LockMutex\n \\sa SDL_TryLockMutex\n \\sa SDL_UnlockMutex"]
    pub fn SDL_CreateMutex() -> *mut SDL_Mutex;
}
extern "C" {
    #[doc = " Lock the mutex.\n\n This will block until the mutex is available, which is to say it is in the\n unlocked state and the OS has chosen the caller as the next thread to lock\n it. Of all threads waiting to lock the mutex, only one may do so at a time.\n\n It is legal for the owning thread to lock an already-locked mutex. It must\n unlock it the same number of times before it is actually made available for\n other threads in the system (this is known as a \"recursive mutex\").\n\n This function does not fail; if mutex is NULL, it will return immediately\n having locked nothing. If the mutex is valid, this function will always\n block until it can lock the mutex, and return with it locked.\n\n \\param mutex the mutex to lock.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_TryLockMutex\n \\sa SDL_UnlockMutex"]
    pub fn SDL_LockMutex(mutex: *mut SDL_Mutex);
}
extern "C" {
    #[doc = " Try to lock a mutex without blocking.\n\n This works just like SDL_LockMutex(), but if the mutex is not available,\n this function returns false immediately.\n\n This technique is useful if you need exclusive access to a resource but\n don't want to wait for it, and will return to it to try again later.\n\n This function returns true if passed a NULL mutex.\n\n \\param mutex the mutex to try to lock.\n \\returns true on success, false if the mutex would block.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_LockMutex\n \\sa SDL_UnlockMutex"]
    pub fn SDL_TryLockMutex(mutex: *mut SDL_Mutex) -> bool;
}
extern "C" {
    #[doc = " Unlock the mutex.\n\n It is legal for the owning thread to lock an already-locked mutex. It must\n unlock it the same number of times before it is actually made available for\n other threads in the system (this is known as a \"recursive mutex\").\n\n It is illegal to unlock a mutex that has not been locked by the current\n thread, and doing so results in undefined behavior.\n\n \\param mutex the mutex to unlock.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_LockMutex\n \\sa SDL_TryLockMutex"]
    pub fn SDL_UnlockMutex(mutex: *mut SDL_Mutex);
}
extern "C" {
    #[doc = " Destroy a mutex created with SDL_CreateMutex().\n\n This function must be called on any mutex that is no longer needed. Failure\n to destroy a mutex will result in a system memory or resource leak. While\n it is safe to destroy a mutex that is _unlocked_, it is not safe to attempt\n to destroy a locked mutex, and may result in undefined behavior depending\n on the platform.\n\n \\param mutex the mutex to destroy.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_CreateMutex"]
    pub fn SDL_DestroyMutex(mutex: *mut SDL_Mutex);
}
#[repr(C)]
#[derive(Debug, Copy, Clone)]
pub struct SDL_RWLock {
    _unused: [u8; 0],
}
extern "C" {
    #[doc = " Create a new read/write lock.\n\n A read/write lock is useful for situations where you have multiple threads\n trying to access a resource that is rarely updated. All threads requesting\n a read-only lock will be allowed to run in parallel; if a thread requests a\n write lock, it will be provided exclusive access. This makes it safe for\n multiple threads to use a resource at the same time if they promise not to\n change it, and when it has to be changed, the rwlock will serve as a\n gateway to make sure those changes can be made safely.\n\n In the right situation, a rwlock can be more efficient than a mutex, which\n only lets a single thread proceed at a time, even if it won't be modifying\n the data.\n\n All newly-created read/write locks begin in the _unlocked_ state.\n\n Calls to SDL_LockRWLockForReading() and SDL_LockRWLockForWriting will not\n return while the rwlock is locked _for writing_ by another thread. See\n SDL_TryLockRWLockForReading() and SDL_TryLockRWLockForWriting() to attempt\n to lock without blocking.\n\n SDL read/write locks are only recursive for read-only locks! They are not\n guaranteed to be fair, or provide access in a FIFO manner! They are not\n guaranteed to favor writers. You may not lock a rwlock for both read-only\n and write access at the same time from the same thread (so you can't\n promote your read-only lock to a write lock without unlocking first).\n\n \\returns the initialized and unlocked read/write lock or NULL on failure;\n          call SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_DestroyRWLock\n \\sa SDL_LockRWLockForReading\n \\sa SDL_LockRWLockForWriting\n \\sa SDL_TryLockRWLockForReading\n \\sa SDL_TryLockRWLockForWriting\n \\sa SDL_UnlockRWLock"]
    pub fn SDL_CreateRWLock() -> *mut SDL_RWLock;
}
extern "C" {
    #[doc = " Lock the read/write lock for _read only_ operations.\n\n This will block until the rwlock is available, which is to say it is not\n locked for writing by any other thread. Of all threads waiting to lock the\n rwlock, all may do so at the same time as long as they are requesting\n read-only access; if a thread wants to lock for writing, only one may do so\n at a time, and no other threads, read-only or not, may hold the lock at the\n same time.\n\n It is legal for the owning thread to lock an already-locked rwlock for\n reading. It must unlock it the same number of times before it is actually\n made available for other threads in the system (this is known as a\n \"recursive rwlock\").\n\n Note that locking for writing is not recursive (this is only available to\n read-only locks).\n\n It is illegal to request a read-only lock from a thread that already holds\n the write lock. Doing so results in undefined behavior. Unlock the write\n lock before requesting a read-only lock. (But, of course, if you have the\n write lock, you don't need further locks to read in any case.)\n\n This function does not fail; if rwlock is NULL, it will return immediately\n having locked nothing. If the rwlock is valid, this function will always\n block until it can lock the mutex, and return with it locked.\n\n \\param rwlock the read/write lock to lock.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_LockRWLockForWriting\n \\sa SDL_TryLockRWLockForReading\n \\sa SDL_UnlockRWLock"]
    pub fn SDL_LockRWLockForReading(rwlock: *mut SDL_RWLock);
}
extern "C" {
    #[doc = " Lock the read/write lock for _write_ operations.\n\n This will block until the rwlock is available, which is to say it is not\n locked for reading or writing by any other thread. Only one thread may hold\n the lock when it requests write access; all other threads, whether they\n also want to write or only want read-only access, must wait until the\n writer thread has released the lock.\n\n It is illegal for the owning thread to lock an already-locked rwlock for\n writing (read-only may be locked recursively, writing can not). Doing so\n results in undefined behavior.\n\n It is illegal to request a write lock from a thread that already holds a\n read-only lock. Doing so results in undefined behavior. Unlock the\n read-only lock before requesting a write lock.\n\n This function does not fail; if rwlock is NULL, it will return immediately\n having locked nothing. If the rwlock is valid, this function will always\n block until it can lock the mutex, and return with it locked.\n\n \\param rwlock the read/write lock to lock.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_LockRWLockForReading\n \\sa SDL_TryLockRWLockForWriting\n \\sa SDL_UnlockRWLock"]
    pub fn SDL_LockRWLockForWriting(rwlock: *mut SDL_RWLock);
}
extern "C" {
    #[doc = " Try to lock a read/write lock _for reading_ without blocking.\n\n This works just like SDL_LockRWLockForReading(), but if the rwlock is not\n available, then this function returns false immediately.\n\n This technique is useful if you need access to a resource but don't want to\n wait for it, and will return to it to try again later.\n\n Trying to lock for read-only access can succeed if other threads are\n holding read-only locks, as this won't prevent access.\n\n This function returns true if passed a NULL rwlock.\n\n \\param rwlock the rwlock to try to lock.\n \\returns true on success, false if the lock would block.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_LockRWLockForReading\n \\sa SDL_TryLockRWLockForWriting\n \\sa SDL_UnlockRWLock"]
    pub fn SDL_TryLockRWLockForReading(rwlock: *mut SDL_RWLock) -> bool;
}
extern "C" {
    #[doc = " Try to lock a read/write lock _for writing_ without blocking.\n\n This works just like SDL_LockRWLockForWriting(), but if the rwlock is not\n available, then this function returns false immediately.\n\n This technique is useful if you need exclusive access to a resource but\n don't want to wait for it, and will return to it to try again later.\n\n It is illegal for the owning thread to lock an already-locked rwlock for\n writing (read-only may be locked recursively, writing can not). Doing so\n results in undefined behavior.\n\n It is illegal to request a write lock from a thread that already holds a\n read-only lock. Doing so results in undefined behavior. Unlock the\n read-only lock before requesting a write lock.\n\n This function returns true if passed a NULL rwlock.\n\n \\param rwlock the rwlock to try to lock.\n \\returns true on success, false if the lock would block.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_LockRWLockForWriting\n \\sa SDL_TryLockRWLockForReading\n \\sa SDL_UnlockRWLock"]
    pub fn SDL_TryLockRWLockForWriting(rwlock: *mut SDL_RWLock) -> bool;
}
extern "C" {
    #[doc = " Unlock the read/write lock.\n\n Use this function to unlock the rwlock, whether it was locked for read-only\n or write operations.\n\n It is legal for the owning thread to lock an already-locked read-only lock.\n It must unlock it the same number of times before it is actually made\n available for other threads in the system (this is known as a \"recursive\n rwlock\").\n\n It is illegal to unlock a rwlock that has not been locked by the current\n thread, and doing so results in undefined behavior.\n\n \\param rwlock the rwlock to unlock.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_LockRWLockForReading\n \\sa SDL_LockRWLockForWriting\n \\sa SDL_TryLockRWLockForReading\n \\sa SDL_TryLockRWLockForWriting"]
    pub fn SDL_UnlockRWLock(rwlock: *mut SDL_RWLock);
}
extern "C" {
    #[doc = " Destroy a read/write lock created with SDL_CreateRWLock().\n\n This function must be called on any read/write lock that is no longer\n needed. Failure to destroy a rwlock will result in a system memory or\n resource leak. While it is safe to destroy a rwlock that is _unlocked_, it\n is not safe to attempt to destroy a locked rwlock, and may result in\n undefined behavior depending on the platform.\n\n \\param rwlock the rwlock to destroy.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_CreateRWLock"]
    pub fn SDL_DestroyRWLock(rwlock: *mut SDL_RWLock);
}
