extern "C" {
    #[doc = " Get the orientation of a display.\n\n \\param displayID the instance ID of the display to query.\n \\returns the SDL_DisplayOrientation enum value of the display, or\n          `SDL_ORIENTATION_UNKNOWN` if it isn't available.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetCurrentDisplayOrientation(
        displayID: SDL_DisplayID,
    ) -> SDL_DisplayOrientation;
}
extern "C" {
    #[doc = " Get the content scale of a display.\n\n The content scale is the expected scale for content based on the DPI\n settings of the display. For example, a 4K display might have a 2.0 (200%)\n display scale, which means that the user expects UI elements to be twice as\n big on this display, to aid in readability.\n\n \\param displayID the instance ID of the display to query.\n \\returns the content scale of the display, or 0.0f on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetDisplayContentScale(displayID: SDL_DisplayID) -> f32;
}
extern "C" {
    #[doc = " Get a list of fullscreen display modes available on a display.\n\n The display modes are sorted in this priority:\n\n - w -> largest to smallest\n - h -> largest to smallest\n - bits per pixel -> more colors to fewer colors\n - packed pixel layout -> largest to smallest\n - refresh rate -> highest to lowest\n - pixel density -> lowest to highest\n\n \\param displayID the instance ID of the display to query.\n \\param count a pointer filled in with the number of display modes returned,\n              may be NULL.\n \\returns a NULL terminated array of display mode pointers or NULL on\n          failure; call SDL_GetError() for more information. This is a\n          single allocation that should be freed with SDL_free() when it is\n          no longer needed.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetFullscreenDisplayModes(
        displayID: SDL_DisplayID,
        count: *mut libc::c_int,
    ) -> *mut *mut SDL_DisplayMode;
}
extern "C" {
    #[doc = " Get the closest match to the requested display mode.\n\n The available display modes are scanned and `closest` is filled in with the\n closest mode matching the requested mode and returned. The mode format and\n refresh rate default to the desktop mode if they are set to 0. The modes\n are scanned with size being first priority, format being second priority,\n and finally checking the refresh rate. If all the available modes are too\n small, then false is returned.\n\n \\param displayID the instance ID of the display to query.\n \\param w the width in pixels of the desired display mode.\n \\param h the height in pixels of the desired display mode.\n \\param refresh_rate the refresh rate of the desired display mode, or 0.0f\n                     for the desktop refresh rate.\n \\param include_high_density_modes boolean to include high density modes in\n                                   the search.\n \\param mode a pointer filled in with the closest display mode equal to or\n             larger than the desired mode.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDisplays\n \\sa SDL_GetFullscreenDisplayModes"]
    pub fn SDL_GetClosestFullscreenDisplayMode(
        displayID: SDL_DisplayID,
        w: libc::c_int,
        h: libc::c_int,
        refresh_rate: f32,
        include_high_density_modes: bool,
        mode: *mut SDL_DisplayMode,
    ) -> bool;
}
extern "C" {
    #[doc = " Get information about the desktop's display mode.\n\n There's a difference between this function and SDL_GetCurrentDisplayMode()\n when SDL runs fullscreen and has changed the resolution. In that case this\n function will return the previous native display mode, and not the current\n display mode.\n\n \\param displayID the instance ID of the display to query.\n \\returns a pointer to the desktop display mode or NULL on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetCurrentDisplayMode\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetDesktopDisplayMode(
        displayID: SDL_DisplayID,
    ) -> *const SDL_DisplayMode;
}
extern "C" {
    #[doc = " Get information about the current display mode.\n\n There's a difference between this function and SDL_GetDesktopDisplayMode()\n when SDL runs fullscreen and has changed the resolution. In that case this\n function will return the current display mode, and not the previous native\n display mode.\n\n \\param displayID the instance ID of the display to query.\n \\returns a pointer to the desktop display mode or NULL on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDesktopDisplayMode\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetCurrentDisplayMode(
        displayID: SDL_DisplayID,
    ) -> *const SDL_DisplayMode;
}
extern "C" {
    #[doc = " Get the display containing a point.\n\n \\param point the point to query.\n \\returns the instance ID of the display containing the point or 0 on\n          failure; call SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDisplayBounds\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetDisplayForPoint(point: *const SDL_Point) -> SDL_DisplayID;
}
extern "C" {
    #[doc = " Get the display primarily containing a rect.\n\n \\param rect the rect to query.\n \\returns the instance ID of the display entirely containing the rect or\n          closest to the center of the rect on success or 0 on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDisplayBounds\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetDisplayForRect(rect: *const SDL_Rect) -> SDL_DisplayID;
}
extern "C" {
    #[doc = " Get the display associated with a window.\n\n \\param window the window to query.\n \\returns the instance ID of the display containing the center of the window\n          on success or 0 on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetDisplayBounds\n \\sa SDL_GetDisplays"]
    pub fn SDL_GetDisplayForWindow(window: *mut SDL_Window) -> SDL_DisplayID;
}
extern "C" {
    #[doc = " Get the pixel density of a window.\n\n This is a ratio of pixel size to window size. For example, if the window is\n 1920x1080 and it has a high density back buffer of 3840x2160 pixels, it\n would have a pixel density of 2.0.\n\n \\param window the window to query.\n \\returns the pixel density or 0.0f on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetWindowDisplayScale"]
    pub fn SDL_GetWindowPixelDensity(window: *mut SDL_Window) -> f32;
}
extern "C" {
    #[doc = " Get the content display scale relative to a window's pixel size.\n\n This is a combination of the window pixel density and the display content\n scale, and is the expected scale for displaying content in this window. For\n example, if a 3840x2160 window had a display scale of 2.0, the user expects\n the content to take twice as many pixels and be the same physical size as\n if it were being displayed in a 1920x1080 window with a display scale of\n 1.0.\n\n Conceptually this value corresponds to the scale display setting, and is\n updated when that setting is changed, or the window moves to a display with\n a different scale setting.\n\n \\param window the window to query.\n \\returns the display scale, or 0.0f on failure; call SDL_GetError() for\n          more information.\n\n \\since This function is available since SDL 3.0.0."]
    pub fn SDL_GetWindowDisplayScale(window: *mut SDL_Window) -> f32;
}
extern "C" {
    #[doc = " Set the display mode to use when a window is visible and fullscreen.\n\n This only affects the display mode used when the window is fullscreen. To\n change the window size when the window is not fullscreen, use\n SDL_SetWindowSize().\n\n If the window is currently in the fullscreen state, this request is\n asynchronous on some windowing systems and the new mode dimensions may not\n be applied immediately upon the return of this function. If an immediate\n change is required, call SDL_SyncWindow() to block until the changes have\n taken effect.\n\n When the new mode takes effect, an SDL_EVENT_WINDOW_RESIZED and/or an\n SDL_EVENT_WINDOW_PIXEL_SIZE_CHANGED event will be emitted with the new mode\n dimensions.\n\n \\param window the window to affect.\n \\param mode a pointer to the display mode to use, which can be NULL for\n             borderless fullscreen desktop mode, or one of the fullscreen\n             modes returned by SDL_GetFullscreenDisplayModes() to set an\n             exclusive fullscreen mode.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetWindowFullscreenMode\n \\sa SDL_SetWindowFullscreen\n \\sa SDL_SyncWindow"]
    pub fn SDL_SetWindowFullscreenMode(
        window: *mut SDL_Window,
        mode: *const SDL_DisplayMode,
    ) -> bool;
}
extern "C" {
    #[doc = " Query the display mode to use when a window is visible at fullscreen.\n\n \\param window the window to query.\n \\returns a pointer to the exclusive fullscreen mode to use or NULL for\n          borderless fullscreen desktop mode.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_SetWindowFullscreenMode\n \\sa SDL_SetWindowFullscreen"]
    pub fn SDL_GetWindowFullscreenMode(
        window: *mut SDL_Window,
    ) -> *const SDL_DisplayMode;
}
extern "C" {
    #[doc = " Get the raw ICC profile data for the screen the window is currently on.\n\n \\param window the window to query.\n \\param size the size of the ICC profile.\n \\returns the raw ICC profile data on success or NULL on failure; call\n          SDL_GetError() for more information. This should be freed with\n          SDL_free() when it is no longer needed.\n\n \\since This function is available since SDL 3.0.0."]
    pub fn SDL_GetWindowICCProfile(
        window: *mut SDL_Window,
        size: *mut usize,
    ) -> *mut libc::c_void;
}
extern "C" {
    #[doc = " Get the pixel format associated with the window.\n\n \\param window the window to query.\n \\returns the pixel format of the window on success or\n          SDL_PIXELFORMAT_UNKNOWN on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0."]
    pub fn SDL_GetWindowPixelFormat(window: *mut SDL_Window) -> SDL_PixelFormat;
}
extern "C" {
    #[doc = " Get a list of valid windows.\n\n \\param count a pointer filled in with the number of windows returned, may\n              be NULL.\n \\returns a NULL terminated array of SDL_Window pointers or NULL on failure;\n          call SDL_GetError() for more information. This is a single\n          allocation that should be freed with SDL_free() when it is no\n          longer needed.\n\n \\since This function is available since SDL 3.0.0."]
    pub fn SDL_GetWindows(count: *mut libc::c_int) -> *mut *mut SDL_Window;
}
extern "C" {
    #[doc = " Create a window with the specified dimensions and flags.\n\n `flags` may be any of the following OR'd together:\n\n - `SDL_WINDOW_FULLSCREEN`: fullscreen window at desktop resolution\n - `SDL_WINDOW_OPENGL`: window usable with an OpenGL context\n - `SDL_WINDOW_OCCLUDED`: window partially or completely obscured by another\n   window\n - `SDL_WINDOW_HIDDEN`: window is not visible\n - `SDL_WINDOW_BORDERLESS`: no window decoration\n - `SDL_WINDOW_RESIZABLE`: window can be resized\n - `SDL_WINDOW_MINIMIZED`: window is minimized\n - `SDL_WINDOW_MAXIMIZED`: window is maximized\n - `SDL_WINDOW_MOUSE_GRABBED`: window has grabbed mouse focus\n - `SDL_WINDOW_INPUT_FOCUS`: window has input focus\n - `SDL_WINDOW_MOUSE_FOCUS`: window has mouse focus\n - `SDL_WINDOW_EXTERNAL`: window not created by SDL\n - `SDL_WINDOW_MODAL`: window is modal\n - `SDL_WINDOW_HIGH_PIXEL_DENSITY`: window uses high pixel density back\n   buffer if possible\n - `SDL_WINDOW_MOUSE_CAPTURE`: window has mouse captured (unrelated to\n   MOUSE_GRABBED)\n - `SDL_WINDOW_ALWAYS_ON_TOP`: window should always be above others\n - `SDL_WINDOW_UTILITY`: window should be treated as a utility window, not\n   showing in the task bar and window list\n - `SDL_WINDOW_TOOLTIP`: window should be treated as a tooltip and does not\n   get mouse or keyboard focus, requires a parent window\n - `SDL_WINDOW_POPUP_MENU`: window should be treated as a popup menu,\n   requires a parent window\n - `SDL_WINDOW_KEYBOARD_GRABBED`: window has grabbed keyboard input\n - `SDL_WINDOW_VULKAN`: window usable with a Vulkan instance\n - `SDL_WINDOW_METAL`: window usable with a Metal instance\n - `SDL_WINDOW_TRANSPARENT`: window with transparent buffer\n - `SDL_WINDOW_NOT_FOCUSABLE`: window should not be focusable\n\n The SDL_Window is implicitly shown if SDL_WINDOW_HIDDEN is not set.\n\n On Apple's macOS, you **must** set the NSHighResolutionCapable Info.plist\n property to YES, otherwise you will not receive a High-DPI OpenGL canvas.\n\n The window pixel size may differ from its window coordinate size if the\n window is on a high pixel density display. Use SDL_GetWindowSize() to query\n the client area's size in window coordinates, and\n SDL_GetWindowSizeInPixels() or SDL_GetRenderOutputSize() to query the\n drawable size in pixels. Note that the drawable size can vary after the\n window is created and should be queried again if you get an\n SDL_EVENT_WINDOW_PIXEL_SIZE_CHANGED event.\n\n If the window is created with any of the SDL_WINDOW_OPENGL or\n SDL_WINDOW_VULKAN flags, then the corresponding LoadLibrary function\n (SDL_GL_LoadLibrary or SDL_Vulkan_LoadLibrary) is called and the\n corresponding UnloadLibrary function is called by SDL_DestroyWindow().\n\n If SDL_WINDOW_VULKAN is specified and there isn't a working Vulkan driver,\n SDL_CreateWindow() will fail, because SDL_Vulkan_LoadLibrary() will fail.\n\n If SDL_WINDOW_METAL is specified on an OS that does not support Metal,\n SDL_CreateWindow() will fail.\n\n If you intend to use this window with an SDL_Renderer, you should use\n SDL_CreateWindowAndRenderer() instead of this function, to avoid window\n flicker.\n\n On non-Apple devices, SDL requires you to either not link to the Vulkan\n loader or link to a dynamic library version. This limitation may be removed\n in a future version of SDL.\n\n \\param title the title of the window, in UTF-8 encoding.\n \\param w the width of the window.\n \\param h the height of the window.\n \\param flags 0, or one or more SDL_WindowFlags OR'd together.\n \\returns the window that was created or NULL on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_CreateWindowAndRenderer\n \\sa SDL_CreatePopupWindow\n \\sa SDL_CreateWindowWithProperties\n \\sa SDL_DestroyWindow"]
    pub fn SDL_CreateWindow(
        title: *const libc::c_char,
        w: libc::c_int,
        h: libc::c_int,
        flags: SDL_WindowFlags,
    ) -> *mut SDL_Window;
}
extern "C" {
    #[doc = " Create a child popup window of the specified parent window.\n\n The flags parameter **must** contain at least one of the following:\n\n - `SDL_WINDOW_TOOLTIP`: The popup window is a tooltip and will not pass any\n   input events.\n - `SDL_WINDOW_POPUP_MENU`: The popup window is a popup menu. The topmost\n   popup menu will implicitly gain the keyboard focus.\n\n The following flags are not relevant to popup window creation and will be\n ignored:\n\n - `SDL_WINDOW_MINIMIZED`\n - `SDL_WINDOW_MAXIMIZED`\n - `SDL_WINDOW_FULLSCREEN`\n - `SDL_WINDOW_BORDERLESS`\n\n The following flags are incompatible with popup window creation and will\n cause it to fail:\n\n - `SDL_WINDOW_UTILITY`\n - `SDL_WINDOW_MODAL`\n\n The parent parameter **must** be non-null and a valid window. The parent of\n a popup window can be either a regular, toplevel window, or another popup\n window.\n\n Popup windows cannot be minimized, maximized, made fullscreen, raised,\n flash, be made a modal window, be the parent of a toplevel window, or grab\n the mouse and/or keyboard. Attempts to do so will fail.\n\n Popup windows implicitly do not have a border/decorations and do not appear\n on the taskbar/dock or in lists of windows such as alt-tab menus.\n\n If a parent window is hidden or destroyed, any child popup windows will be\n recursively hidden or destroyed as well. Child popup windows not explicitly\n hidden will be restored when the parent is shown.\n\n \\param parent the parent of the window, must not be NULL.\n \\param offset_x the x position of the popup window relative to the origin\n                 of the parent.\n \\param offset_y the y position of the popup window relative to the origin\n                 of the parent window.\n \\param w the width of the window.\n \\param h the height of the window.\n \\param flags SDL_WINDOW_TOOLTIP or SDL_WINDOW_POPUP_MENU, and zero or more\n              additional SDL_WindowFlags OR'd together.\n \\returns the window that was created or NULL on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_CreateWindow\n \\sa SDL_CreateWindowWithProperties\n \\sa SDL_DestroyWindow\n \\sa SDL_GetWindowParent"]
    pub fn SDL_CreatePopupWindow(
        parent: *mut SDL_Window,
        offset_x: libc::c_int,
        offset_y: libc::c_int,
        w: libc::c_int,
        h: libc::c_int,
        flags: SDL_WindowFlags,
    ) -> *mut SDL_Window;
}
extern "C" {
    #[doc = " Create a window with the specified properties.\n\n These are the supported properties:\n\n - `SDL_PROP_WINDOW_CREATE_ALWAYS_ON_TOP_BOOLEAN`: true if the window should\n   be always on top\n - `SDL_PROP_WINDOW_CREATE_BORDERLESS_BOOLEAN`: true if the window has no\n   window decoration\n - `SDL_PROP_WINDOW_CREATE_EXTERNAL_GRAPHICS_CONTEXT_BOOLEAN`: true if the\n   window will be used with an externally managed graphics context.\n - `SDL_PROP_WINDOW_CREATE_FOCUSABLE_BOOLEAN`: true if the window should\n   accept keyboard input (defaults true)\n - `SDL_PROP_WINDOW_CREATE_FULLSCREEN_BOOLEAN`: true if the window should\n   start in fullscreen mode at desktop resolution\n - `SDL_PROP_WINDOW_CREATE_HEIGHT_NUMBER`: the height of the window\n - `SDL_PROP_WINDOW_CREATE_HIDDEN_BOOLEAN`: true if the window should start\n   hidden\n - `SDL_PROP_WINDOW_CREATE_HIGH_PIXEL_DENSITY_BOOLEAN`: true if the window\n   uses a high pixel density buffer if possible\n - `SDL_PROP_WINDOW_CREATE_MAXIMIZED_BOOLEAN`: true if the window should\n   start maximized\n - `SDL_PROP_WINDOW_CREATE_MENU_BOOLEAN`: true if the window is a popup menu\n - `SDL_PROP_WINDOW_CREATE_METAL_BOOLEAN`: true if the window will be used\n   with Metal rendering\n - `SDL_PROP_WINDOW_CREATE_MINIMIZED_BOOLEAN`: true if the window should\n   start minimized\n - `SDL_PROP_WINDOW_CREATE_MODAL_BOOLEAN`: true if the window is modal to\n   its parent\n - `SDL_PROP_WINDOW_CREATE_MOUSE_GRABBED_BOOLEAN`: true if the window starts\n   with grabbed mouse focus\n - `SDL_PROP_WINDOW_CREATE_OPENGL_BOOLEAN`: true if the window will be used\n   with OpenGL rendering\n - `SDL_PROP_WINDOW_CREATE_PARENT_POINTER`: an SDL_Window that will be the\n   parent of this window, required for windows with the \"tooltip\", \"menu\",\n   and \"modal\" properties\n - `SDL_PROP_WINDOW_CREATE_RESIZABLE_BOOLEAN`: true if the window should be\n   resizable\n - `SDL_PROP_WINDOW_CREATE_TITLE_STRING`: the title of the window, in UTF-8\n   encoding\n - `SDL_PROP_WINDOW_CREATE_TRANSPARENT_BOOLEAN`: true if the window show\n   transparent in the areas with alpha of 0\n - `SDL_PROP_WINDOW_CREATE_TOOLTIP_BOOLEAN`: true if the window is a tooltip\n - `SDL_PROP_WINDOW_CREATE_UTILITY_BOOLEAN`: true if the window is a utility\n   window, not showing in the task bar and window list\n - `SDL_PROP_WINDOW_CREATE_VULKAN_BOOLEAN`: true if the window will be used\n   with Vulkan rendering\n - `SDL_PROP_WINDOW_CREATE_WIDTH_NUMBER`: the width of the window\n - `SDL_PROP_WINDOW_CREATE_X_NUMBER`: the x position of the window, or\n   `SDL_WINDOWPOS_CENTERED`, defaults to `SDL_WINDOWPOS_UNDEFINED`. This is\n   relative to the parent for windows with the \"parent\" property set.\n - `SDL_PROP_WINDOW_CREATE_Y_NUMBER`: the y position of the window, or\n   `SDL_WINDOWPOS_CENTERED`, defaults to `SDL_WINDOWPOS_UNDEFINED`. This is\n   relative to the parent for windows with the \"parent\" property set.\n\n These are additional supported properties on macOS:\n\n - `SDL_PROP_WINDOW_CREATE_COCOA_WINDOW_POINTER`: the\n   `(__unsafe_unretained)` NSWindow associated with the window, if you want\n   to wrap an existing window.\n - `SDL_PROP_WINDOW_CREATE_COCOA_VIEW_POINTER`: the `(__unsafe_unretained)`\n   NSView associated with the window, defaults to `[window contentView]`\n\n These are additional supported properties on Wayland:\n\n - `SDL_PROP_WINDOW_CREATE_WAYLAND_SURFACE_ROLE_CUSTOM_BOOLEAN` - true if\n   the application wants to use the Wayland surface for a custom role and\n   does not want it attached to an XDG toplevel window. See\n   [README/wayland](README/wayland) for more information on using custom\n   surfaces.\n - `SDL_PROP_WINDOW_CREATE_WAYLAND_CREATE_EGL_WINDOW_BOOLEAN` - true if the\n   application wants an associated `wl_egl_window` object to be created and\n   attached to the window, even if the window does not have the OpenGL\n   property or `SDL_WINDOW_OPENGL` flag set.\n - `SDL_PROP_WINDOW_CREATE_WAYLAND_WL_SURFACE_POINTER` - the wl_surface\n   associated with the window, if you want to wrap an existing window. See\n   [README/wayland](README/wayland) for more information.\n\n These are additional supported properties on Windows:\n\n - `SDL_PROP_WINDOW_CREATE_WIN32_HWND_POINTER`: the HWND associated with the\n   window, if you want to wrap an existing window.\n - `SDL_PROP_WINDOW_CREATE_WIN32_PIXEL_FORMAT_HWND_POINTER`: optional,\n   another window to share pixel format with, useful for OpenGL windows\n\n These are additional supported properties with X11:\n\n - `SDL_PROP_WINDOW_CREATE_X11_WINDOW_NUMBER`: the X11 Window associated\n   with the window, if you want to wrap an existing window.\n\n The window is implicitly shown if the \"hidden\" property is not set.\n\n Windows with the \"tooltip\" and \"menu\" properties are popup windows and have\n the behaviors and guidelines outlined in SDL_CreatePopupWindow().\n\n If this window is being created to be used with an SDL_Renderer, you should\n not add a graphics API specific property\n (`SDL_PROP_WINDOW_CREATE_OPENGL_BOOLEAN`, etc), as SDL will handle that\n internally when it chooses a renderer. However, SDL might need to recreate\n your window at that point, which may cause the window to appear briefly,\n and then flicker as it is recreated. The correct approach to this is to\n create the window with the `SDL_PROP_WINDOW_CREATE_HIDDEN_BOOLEAN` property\n set to true, then create the renderer, then show the window with\n SDL_ShowWindow().\n\n \\param props the properties to use.\n \\returns the window that was created or NULL on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_CreateProperties\n \\sa SDL_CreateWindow\n \\sa SDL_DestroyWindow"]
    pub fn SDL_CreateWindowWithProperties(
        props: SDL_PropertiesID,
    ) -> *mut SDL_Window;
}
