extern "C" {
    #[doc = " Set the icon for a window.\n\n If this function is passed a surface with alternate representations, the\n surface will be interpreted as the content to be used for 100% display\n scale, and the alternate representations will be used for high DPI\n situations. For example, if the original surface is 32x32, then on a 2x\n macOS display or 200% display scale on Windows, a 64x64 version of the\n image will be used, if available. If a matching version of the image isn't\n available, the closest larger size image will be downscaled to the\n appropriate size and be used instead, if available. Otherwise, the closest\n smaller image will be upscaled and be used instead.\n\n \\param window the window to change.\n \\param icon an SDL_Surface structure containing the icon for the window.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0."]
    pub fn SDL_SetWindowIcon(
        window: *mut SDL_Window,
        icon: *mut SDL_Surface,
    ) -> bool;
}
extern "C" {
    #[doc = " Request that the window's position be set.\n\n If, at the time of this request, the window is in a fixed-size state such\n as maximized, this request may be deferred until the window returns to a\n resizable state.\n\n This can be used to reposition fullscreen-desktop windows onto a different\n display, however, exclusive fullscreen windows are locked to a specific\n display and can only be repositioned programmatically via\n SDL_SetWindowFullscreenMode().\n\n On some windowing systems this request is asynchronous and the new\n coordinates may not have have been applied immediately upon the return of\n this function. If an immediate change is required, call SDL_SyncWindow() to\n block until the changes have taken effect.\n\n When the window position changes, an SDL_EVENT_WINDOW_MOVED event will be\n emitted with the window's new coordinates. Note that the new coordinates\n may not match the exact coordinates requested, as some windowing systems\n can restrict the position of the window in certain scenarios (e.g.\n constraining the position so the window is always within desktop bounds).\n Additionally, as this is just a request, it can be denied by the windowing\n system.\n\n \\param window the window to reposition.\n \\param x the x coordinate of the window, or `SDL_WINDOWPOS_CENTERED` or\n          `SDL_WINDOWPOS_UNDEFINED`.\n \\param y the y coordinate of the window, or `SDL_WINDOWPOS_CENTERED` or\n          `SDL_WINDOWPOS_UNDEFINED`.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetWindowPosition\n \\sa SDL_SyncWindow"]
    pub fn SDL_SetWindowPosition(
        window: *mut SDL_Window,
        x: libc::c_int,
        y: libc::c_int,
    ) -> bool;
}
extern "C" {
    #[doc = " Get the position of a window.\n\n This is the current position of the window as last reported by the\n windowing system.\n\n If you do not need the value for one of the positions a NULL may be passed\n in the `x` or `y` parameter.\n\n \\param window the window to query.\n \\param x a pointer filled in with the x position of the window, may be\n          NULL.\n \\param y a pointer filled in with the y position of the window, may be\n          NULL.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_SetWindowPosition"]
    pub fn SDL_GetWindowPosition(
        window: *mut SDL_Window,
        x: *mut libc::c_int,
        y: *mut libc::c_int,
    ) -> bool;
}
extern "C" {
    #[doc = " Request that the size of a window's client area be set.\n\n If, at the time of this request, the window in a fixed-size state, such as\n maximized or fullscreen, the request will be deferred until the window\n exits this state and becomes resizable again.\n\n To change the fullscreen mode of a window, use\n SDL_SetWindowFullscreenMode()\n\n On some windowing systems, this request is asynchronous and the new window\n size may not have have been applied immediately upon the return of this\n function. If an immediate change is required, call SDL_SyncWindow() to\n block until the changes have taken effect.\n\n When the window size changes, an SDL_EVENT_WINDOW_RESIZED event will be\n emitted with the new window dimensions. Note that the new dimensions may\n not match the exact size requested, as some windowing systems can restrict\n the window size in certain scenarios (e.g. constraining the size of the\n content area to remain within the usable desktop bounds). Additionally, as\n this is just a request, it can be denied by the windowing system.\n\n \\param window the window to change.\n \\param w the width of the window, must be > 0.\n \\param h the height of the window, must be > 0.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetWindowSize\n \\sa SDL_SetWindowFullscreenMode\n \\sa SDL_SyncWindow"]
    pub fn SDL_SetWindowSize(
        window: *mut SDL_Window,
        w: libc::c_int,
        h: libc::c_int,
    ) -> bool;
}
extern "C" {
    #[doc = " Get the size of a window's client area.\n\n The window pixel size may differ from its window coordinate size if the\n window is on a high pixel density display. Use SDL_GetWindowSizeInPixels()\n or SDL_GetRenderOutputSize() to get the real client area size in pixels.\n\n \\param window the window to query the width and height from.\n \\param w a pointer filled in with the width of the window, may be NULL.\n \\param h a pointer filled in with the height of the window, may be NULL.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetRenderOutputSize\n \\sa SDL_GetWindowSizeInPixels\n \\sa SDL_SetWindowSize"]
    pub fn SDL_GetWindowSize(
        window: *mut SDL_Window,
        w: *mut libc::c_int,
        h: *mut libc::c_int,
    ) -> bool;
}
extern "C" {
    #[doc = " Get the safe area for this window.\n\n Some devices have portions of the screen which are partially obscured or\n not interactive, possibly due to on-screen controls, curved edges, camera\n notches, TV overscan, etc. This function provides the area of the window\n which is safe to have interactable content. You should continue rendering\n into the rest of the window, but it should not contain visually important\n or interactible content.\n\n \\param window the window to query.\n \\param rect a pointer filled in with the client area that is safe for\n             interactive content.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0."]
    pub fn SDL_GetWindowSafeArea(
        window: *mut SDL_Window,
        rect: *mut SDL_Rect,
    ) -> bool;
}
extern "C" {
    #[doc = " Request that the aspect ratio of a window's client area be set.\n\n The aspect ratio is the ratio of width divided by height, e.g. 2560x1600\n would be 1.6. Larger aspect ratios are wider and smaller aspect ratios are\n narrower.\n\n If, at the time of this request, the window in a fixed-size state, such as\n maximized or fullscreen, the request will be deferred until the window\n exits this state and becomes resizable again.\n\n On some windowing systems, this request is asynchronous and the new window\n aspect ratio may not have have been applied immediately upon the return of\n this function. If an immediate change is required, call SDL_SyncWindow() to\n block until the changes have taken effect.\n\n When the window size changes, an SDL_EVENT_WINDOW_RESIZED event will be\n emitted with the new window dimensions. Note that the new dimensions may\n not match the exact aspect ratio requested, as some windowing systems can\n restrict the window size in certain scenarios (e.g. constraining the size\n of the content area to remain within the usable desktop bounds).\n Additionally, as this is just a request, it can be denied by the windowing\n system.\n\n \\param window the window to change.\n \\param min_aspect the minimum aspect ratio of the window, or 0.0f for no\n                   limit.\n \\param max_aspect the maximum aspect ratio of the window, or 0.0f for no\n                   limit.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetWindowAspectRatio\n \\sa SDL_SyncWindow"]
    pub fn SDL_SetWindowAspectRatio(
        window: *mut SDL_Window,
        min_aspect: f32,
        max_aspect: f32,
    ) -> bool;
}
extern "C" {
    #[doc = " Get the size of a window's client area.\n\n \\param window the window to query the width and height from.\n \\param min_aspect a pointer filled in with the minimum aspect ratio of the\n                   window, may be NULL.\n \\param max_aspect a pointer filled in with the maximum aspect ratio of the\n                   window, may be NULL.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_SetWindowAspectRatio"]
    pub fn SDL_GetWindowAspectRatio(
        window: *mut SDL_Window,
        min_aspect: *mut f32,
        max_aspect: *mut f32,
    ) -> bool;
}
extern "C" {
    #[doc = " Get the size of a window's borders (decorations) around the client area.\n\n Note: If this function fails (returns false), the size values will be\n initialized to 0, 0, 0, 0 (if a non-NULL pointer is provided), as if the\n window in question was borderless.\n\n Note: This function may fail on systems where the window has not yet been\n decorated by the display server (for example, immediately after calling\n SDL_CreateWindow). It is recommended that you wait at least until the\n window has been presented and composited, so that the window system has a\n chance to decorate the window and provide the border dimensions to SDL.\n\n This function also returns false if getting the information is not\n supported.\n\n \\param window the window to query the size values of the border\n               (decorations) from.\n \\param top pointer to variable for storing the size of the top border; NULL\n            is permitted.\n \\param left pointer to variable for storing the size of the left border;\n             NULL is permitted.\n \\param bottom pointer to variable for storing the size of the bottom\n               border; NULL is permitted.\n \\param right pointer to variable for storing the size of the right border;\n              NULL is permitted.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetWindowSize"]
    pub fn SDL_GetWindowBordersSize(
        window: *mut SDL_Window,
        top: *mut libc::c_int,
        left: *mut libc::c_int,
        bottom: *mut libc::c_int,
        right: *mut libc::c_int,
    ) -> bool;
}
