#[doc = " An SDL_GUID is a 128-bit identifier for an input device that identifies\n that device across runs of SDL programs on the same platform.\n\n If the device is detached and then re-attached to a different port, or if\n the base system is rebooted, the device should still report the same GUID.\n\n GUIDs are as precise as possible but are not guaranteed to distinguish\n physically distinct but equivalent devices. For example, two game\n controllers from the same vendor with the same product ID and revision may\n have the same GUID.\n\n GUIDs may be platform-dependent (i.e., the same device may report different\n GUIDs on different operating systems).\n\n \\since This struct is available since SDL 3.0.0."]
#[repr(C)]
#[derive(Debug, Copy, Clone)]
pub struct SDL_GUID {
    pub data: [Uint8; 16usize],
}
extern "C" {
    #[doc = " Get an ASCII string representation for a given SDL_GUID.\n\n \\param guid the SDL_GUID you wish to convert to string.\n \\param pszGUID buffer in which to write the ASCII string.\n \\param cbGUID the size of pszGUID, should be at least 33 bytes.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_StringToGUID"]
    pub fn SDL_GUIDToString(
        guid: SDL_GUID,
        pszGUID: *mut libc::c_char,
        cbGUID: libc::c_int,
    );
}
extern "C" {
    #[doc = " Convert a GUID string into a SDL_GUID structure.\n\n Performs no error checking. If this function is given a string containing\n an invalid GUID, the function will silently succeed, but the GUID generated\n will not be useful.\n\n \\param pchGUID string containing an ASCII representation of a GUID.\n \\returns a SDL_GUID structure.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GUIDToString"]
    pub fn SDL_StringToGUID(pchGUID: *const libc::c_char) -> SDL_GUID;
}
