#[derive(Debug, Copy, Clone, Hash, PartialEq, Eq)]
pub enum SDL_EventAction {
    #[doc = "< Add events to the back of the queue."]
    SDL_ADDEVENT = 0,
    #[doc = "< Check but don't remove events from the queue front."]
    SDL_PEEKEVENT = 1,
    #[doc = "< Retrieve/remove events from the front of the queue."]
    SDL_GETEVENT = 2,
}
extern "C" {
    #[doc = " Check the event queue for messages and optionally return them.\n\n `action` may be any of the following:\n\n - `SDL_ADDEVENT`: up to `numevents` events will be added to the back of the\n   event queue.\n - `SDL_PEEKEVENT`: `numevents` events at the front of the event queue,\n   within the specified minimum and maximum type, will be returned to the\n   caller and will _not_ be removed from the queue. If you pass NULL for\n   `events`, then `numevents` is ignored and the total number of matching\n   events will be returned.\n - `SDL_GETEVENT`: up to `numevents` events at the front of the event queue,\n   within the specified minimum and maximum type, will be returned to the\n   caller and will be removed from the queue.\n\n You may have to call SDL_PumpEvents() before calling this function.\n Otherwise, the events may not be ready to be filtered when you call\n SDL_PeepEvents().\n\n This function is thread-safe.\n\n \\param events destination buffer for the retrieved events, may be NULL to\n               leave the events in the queue and return the number of events\n               that would have been stored.\n \\param numevents if action is SDL_ADDEVENT, the number of events to add\n                  back to the event queue; if action is SDL_PEEKEVENT or\n                  SDL_GETEVENT, the maximum number of events to retrieve.\n \\param action action to take; see [[#action|Remarks]] for details.\n \\param minType minimum value of the event type to be considered;\n                SDL_EVENT_FIRST is a safe choice.\n \\param maxType maximum value of the event type to be considered;\n                SDL_EVENT_LAST is a safe choice.\n \\returns the number of events actually stored or -1 on failure; call\n          SDL_GetError() for more information.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_PollEvent\n \\sa SDL_PumpEvents\n \\sa SDL_PushEvent"]
    pub fn SDL_PeepEvents(
        events: *mut SDL_Event,
        numevents: libc::c_int,
        action: SDL_EventAction,
        minType: Uint32,
        maxType: Uint32,
    ) -> libc::c_int;
}
