extern "C" {
    #[doc = " Specify basic metadata about your app.\n\n You can optionally provide metadata about your app to SDL. This is not\n required, but strongly encouraged.\n\n There are several locations where SDL can make use of metadata (an \"About\"\n box in the macOS menu bar, the name of the app can be shown on some audio\n mixers, etc). Any piece of metadata can be left as NULL, if a specific\n detail doesn't make sense for the app.\n\n This function should be called as early as possible, before SDL_Init.\n Multiple calls to this function are allowed, but various state might not\n change once it has been set up with a previous call to this function.\n\n Passing a NULL removes any previous metadata.\n\n This is a simplified interface for the most important information. You can\n supply significantly more detailed metadata with\n SDL_SetAppMetadataProperty().\n\n \\param appname The name of the application (\"My Game 2: Bad Guy's\n                Revenge!\").\n \\param appversion The version of the application (\"1.0.0beta5\" or a git\n                   hash, or whatever makes sense).\n \\param appidentifier A unique string in reverse-domain format that\n                      identifies this app (\"com.example.mygame2\").\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\threadsafety It is safe to call this function from any thread.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_SetAppMetadataProperty"]
    pub fn SDL_SetAppMetadata(
        appname: *const libc::c_char,
        appversion: *const libc::c_char,
        appidentifier: *const libc::c_char,
    ) -> bool;
}
extern "C" {
    #[doc = " Specify metadata about your app through a set of properties.\n\n You can optionally provide metadata about your app to SDL. This is not\n required, but strongly encouraged.\n\n There are several locations where SDL can make use of metadata (an \"About\"\n box in the macOS menu bar, the name of the app can be shown on some audio\n mixers, etc). Any piece of metadata can be left out, if a specific detail\n doesn't make sense for the app.\n\n This function should be called as early as possible, before SDL_Init.\n Multiple calls to this function are allowed, but various state might not\n change once it has been set up with a previous call to this function.\n\n Once set, this metadata can be read using SDL_GetMetadataProperty().\n\n These are the supported properties:\n\n - `SDL_PROP_APP_METADATA_NAME_STRING`: The human-readable name of the\n   application, like \"My Game 2: Bad Guy's Revenge!\". This will show up\n   anywhere the OS shows the name of the application separately from window\n   titles, such as volume control applets, etc. This defaults to \"SDL\n   Application\".\n - `SDL_PROP_APP_METADATA_VERSION_STRING`: The version of the app that is\n   running; there are no rules on format, so \"1.0.3beta2\" and \"April 22nd,\n   2024\" and a git hash are all valid options. This has no default.\n - `SDL_PROP_APP_METADATA_IDENTIFIER_STRING`: A unique string that\n   identifies this app. This must be in reverse-domain format, like\n   \"com.example.mygame2\". This string is used by desktop compositors to\n   identify and group windows together, as well as match applications with\n   associated desktop settings and icons. If you plan to package your\n   application in a container such as Flatpak, the app ID should match the\n   name of your Flatpak container as well. This has no default.\n - `SDL_PROP_APP_METADATA_CREATOR_STRING`: The human-readable name of the\n   creator/developer/maker of this app, like \"MojoWorkshop, LLC\"\n - `SDL_PROP_APP_METADATA_COPYRIGHT_STRING`: The human-readable copyright\n   notice, like \"Copyright (c) 2024 MojoWorkshop, LLC\" or whatnot. Keep this\n   to one line, don't paste a copy of a whole software license in here. This\n   has no default.\n - `SDL_PROP_APP_METADATA_URL_STRING`: A URL to the app on the web. Maybe a\n   product page, or a storefront, or even a GitHub repository, for user's\n   further information This has no default.\n - `SDL_PROP_APP_METADATA_TYPE_STRING`: The type of application this is.\n   Currently this string can be \"game\" for a video game, \"mediaplayer\" for a\n   media player, or generically \"application\" if nothing else applies.\n   Future versions of SDL might add new types. This defaults to\n   \"application\".\n\n \\param name the name of the metadata property to set.\n \\param value the value of the property, or NULL to remove that property.\n \\returns true on success or false on failure; call SDL_GetError() for more\n          information.\n\n \\threadsafety It is safe to call this function from any thread.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetAppMetadataProperty\n \\sa SDL_SetAppMetadata"]
    pub fn SDL_SetAppMetadataProperty(
        name: *const libc::c_char,
        value: *const libc::c_char,
    ) -> bool;
}
extern "C" {
    #[doc = " Get metadata about your app.\n\n This returns metadata previously set using SDL_SetAppMetadata() or\n SDL_SetAppMetadataProperty(). See SDL_SetAppMetadataProperty() for the list\n of available properties and their meanings.\n\n \\param name the name of the metadata property to get.\n \\returns the current value of the metadata property, or the default if it\n          is not set, NULL for properties with no default.\n\n \\threadsafety It is safe to call this function from any thread, although\n               the string returned is not protected and could potentially be\n               freed if you call SDL_SetAppMetadataProperty() to set that\n               property from another thread.\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_SetAppMetadata\n \\sa SDL_SetAppMetadataProperty"]
    pub fn SDL_GetAppMetadataProperty(
        name: *const libc::c_char,
    ) -> *const libc::c_char;
}
