#[doc = " A struct to provide locale data.\n\n Locale data is split into a spoken language, like English, and an optional\n country, like Canada. The language will be in ISO-639 format (so English\n would be \"en\"), and the country, if not NULL, will be an ISO-3166 country\n code (so Canada would be \"CA\").\n\n \\since This function is available since SDL 3.0.0.\n\n \\sa SDL_GetPreferredLocales"]
#[repr(C)]
#[derive(Debug, Copy, Clone)]
pub struct SDL_Locale {
    #[doc = "< A language name, like \"en\" for English."]
    pub language: *const libc::c_char,
    #[doc = "< A country, like \"US\" for America. Can be NULL."]
    pub country: *const libc::c_char,
}
extern "C" {
    #[doc = " Report the user's preferred locale.\n\n Returned language strings are in the format xx, where 'xx' is an ISO-639\n language specifier (such as \"en\" for English, \"de\" for German, etc).\n Country strings are in the format YY, where \"YY\" is an ISO-3166 country\n code (such as \"US\" for the United States, \"CA\" for Canada, etc). Country\n might be NULL if there's no specific guidance on them (so you might get {\n \"en\", \"US\" } for American English, but { \"en\", NULL } means \"English\n language, generically\"). Language strings are never NULL, except to\n terminate the array.\n\n Please note that not all of these strings are 2 characters; some are three\n or more.\n\n The returned list of locales are in the order of the user's preference. For\n example, a German citizen that is fluent in US English and knows enough\n Japanese to navigate around Tokyo might have a list like: { \"de\", \"en_US\",\n \"jp\", NULL }. Someone from England might prefer British English (where\n \"color\" is spelled \"colour\", etc), but will settle for anything like it: {\n \"en_GB\", \"en\", NULL }.\n\n This function returns NULL on error, including when the platform does not\n supply this information at all.\n\n This might be a \"slow\" call that has to query the operating system. It's\n best to ask for this once and save the results. However, this list can\n change, usually because the user has changed a system preference outside of\n your program; SDL will send an SDL_EVENT_LOCALE_CHANGED event in this case,\n if possible, and you can call this function again to get an updated copy of\n preferred locales.\n\n \\param count a pointer filled in with the number of locales returned, may\n              be NULL.\n \\returns a NULL terminated array of locale pointers, or NULL on failure;\n          call SDL_GetError() for more information. This is a single\n          allocation that should be freed with SDL_free() when it is no\n          longer needed.\n\n \\since This function is available since SDL 3.0.0."]
    pub fn SDL_GetPreferredLocales(count: *mut libc::c_int) -> *mut *mut SDL_Locale;
}
